mapper.select:
SELECT FAQ_ID as faqId, QESTN_SJ as qestnSj, QESTN_CN as qestnCn, ANSWER_CN as answerCn, RDCNT AS inqireCo, ATCH_FILE_ID as atchFileId, DATE_FORMAT(FRST_REGIST_PNTTM, '%Y-%m-%d') as frstRegisterPnttm, FRST_REGISTER_ID as frstRegisterId, DATE_FORMAT(LAST_UPDT_PNTTM,'%Y-%m-%d') as lastUpdusrPnttm, LAST_UPDUSR_ID as lastUpdusrId FROM LETTNFAQINFO WHERE 1=1
AND QESTN_SJ LIKE CONCAT('%', #{searchKeyword}, '%')
ORDER BY FAQ_ID DESC LIMIT #{recordCountPerPage} OFFSET #{firstIndex}

mapper.update:
			UPDATE	LETTNFAQINFO	SET
				    RDCNT= IFNULL(RDCNT,0) + 1				  			
				  , LAST_UPDT_PNTTM=sysdate()
				  , LAST_UPDUSR_ID=#{lastUpdusrId}
 			WHERE  FAQ_ID=#{faqId}

			UPDATE	LETTNFAQINFO	SET
					FAQ_ID=#{faqId} 
				  , QESTN_SJ=#{qestnSj}
				  , QESTN_CN=#{qestnCn}
				  , ANSWER_CN=#{answerCn}
				  , ATCH_FILE_ID=#{atchFileId}				  			
				  , LAST_UPDT_PNTTM=sysdate()
				  , LAST_UPDUSR_ID=#{lastUpdusrId}
 			WHERE  FAQ_ID=#{faqId}
